最后是代码最长的AI，EndermanLookForPlayerGoal。Wiki上这样写：“玩家在64格距离内注视末影人的头部达到5游戏刻（0.25秒）也会激怒它们。”，这是怎么实现的呢？
static class EndermanLookForPlayerGoal extends NearestAttackableTargetGoal {
    private final EnderMan enderman;
    @Nullable
    private Player pendingTarget;
    private int aggroTime;
    private int teleportTime;
    private final TargetingConditions startAggroTargetConditions;
    private final TargetingConditions continueAggroTargetConditions = TargetingConditions.forCombat().ignoreLineOfSight();
    private final Predicate isAngerInducing;

    public EndermanLookForPlayerGoal(EnderMan enderman, @Nullable Predicate targetConditions) {
        super(enderman, Player.class, 10, false, false, targetConditions);
        this.enderman = enderman;
        this.isAngerInducing = entity -> (enderman.isLookingAtMe((Player) entity) || enderman.isAngryAt(entity)) && !enderman.hasIndirectPassenger(entity);
        // TargetingConditions里forCombat和forNonCombat的区别在于forCombat会检查是否是和平模式以及target是否为队友，而forNonCombat不会
        this.startAggroTargetConditions = TargetingConditions.forCombat().range(getFollowDistance()).selector(isAngerInducing);
    }

    @Override
    public boolean canUse() {
    //  pendingTarget，指待定的攻击目标
        pendingTarget = enderman.level().getNearestPlayer(startAggroTargetConditions, enderman);
        return pendingTarget != null;
    }

    @Override
    public void start() {
        aggroTime = adjustedTickDelay(5);
        teleportTime = 0;
        enderman.setBeingStaredAt();
    }

    @Override
    public void stop() {
        pendingTarget = null;
        super.stop();
    }

    @Override
    public boolean canContinueToUse() {
        if (pendingTarget != null) {
            if (!isAngerInducing.test(pendingTarget)) {
                return false;
            } else {
            //  lookAt的后两个float参数分别表示最大的yRot，最大的xRot
                enderman.lookAt(pendingTarget, 10.0F, 10.0F);
                return true;
            }
        } else {
            if (target != null) {
                if (enderman.hasIndirectPassenger(target)) {
                    return false;
                }
                if (continueAggroTargetConditions.test(enderman, target)) {
                    return true;
                }
            }
            return super.canContinueToUse();
        }
    }

    @Override
    public void tick() {
        if (enderman.getTarget() == null) {
            super.setTarget(null);
        }
        if (pendingTarget != null) {
            if (--aggroTime  256.0D && teleportTime++ >= adjustedTickDelay(30) && enderman.teleportTowards(target)) {
                    teleportTime = 0;
                }
            }
            super.tick();
        }
    }
}

EndermanLookForPlayerGoal中先用pendingTarget临时记录了待定的攻击目标，等到注视5游戏刻后，再将其设置为真正的攻击目标。注意canUse被重写了，也就是说只要附近有玩家，这个AI就会“start”。
本节的内容就到此为止了，下一节将会简单讲一下末影人的模型与渲染~

part1-monster/melee/enderman3.html.body:
末影人的模型与渲染
本节将主要分析末影人的模型的特殊之处，以及末影人的渲染器中使用的Layer（RenderLayer，不是旧版生物群系使用的Layer）
先是成员变量与构造方法。
@OnlyIn(Dist.CLIENT)
public class EndermanModel extends HumanoidModel {
//  决定了末影人是否在搬着方块，值为true则表示正在搬着方块
    public boolean carrying;
//  决定了末影人是否处于愤怒状态，值为true则意味着处于愤怒状态
    public boolean creepy;

    public EndermanModel(ModelPart part) {
        super(part);
    }
}

因为末影人有2组不同的状态（生气-不生气，搬着方块-空手），所以模型中有两个公共且可变的boolean成员变量，用来控制末影人的模型。实际开发中，不提倡这种暴露成员变量的方式，尽量使用getter和setter。  
然后是静态方法createBodyLayer，因为末影人的模型与标准的“人类模型”不同，所以要重新写一个LayerDefinition。
public static LayerDefinition createBodyLayer() {
    MeshDefinition meshDef = HumanoidModel.createMesh(CubeDeformation.NONE, -14.0F);
    PartDefinition partDef = meshDef.getRoot();
    PartPose head = PartPose.offset(0.0F, -13.0F, 0.0F); // part的相对位置（x, y, z）
    partDef.addOrReplaceChild("hat",
//          此处与较早的MC版本定义模型的方式不同，材质位置，box的大小、位置、缩放比例都在PartDefinition中而不是ModelPart中定义
            CubeListBuilder.create()
                    .texOffs(0, 16) // 材质的uv位置
                    .addBox(-4.0F, -8.0F, -4.0F, // box的相对位置（x, y, z）
                            8.0F, 8.0F, 8.0F, // box的大小（x, y, z）
                            new CubeDeformation(-0.5F) // 缩放比例（正值放大，负值收缩）
                    ),
            head);
    partDef.addOrReplaceChild("head", CubeListBuilder.create().texOffs(0, 0).addBox(-4.0F, -8.0F, -4.0F, 8.0F, 8.0F, 8.0F), head);
    partDef.addOrReplaceChild("body", CubeListBuilder.create().texOffs(32, 16).addBox(-4.0F, 0.0F, -2.0F, 8.0F, 12.0F, 4.0F), PartPose.offset(0.0F, -14.0F, 0.0F));
    partDef.addOrReplaceChild("right_arm", CubeListBuilder.create().texOffs(56, 0).addBox(-1.0F, -2.0F, -1.0F, 2.0F, 30.0F, 2.0F), PartPose.offset(-5.0F, -12.0F, 0.0F));
    partDef.addOrReplaceChild("left_arm", CubeListBuilder.create().texOffs(56, 0).mirror().addBox(-1.0F, -2.0F, -1.0F, 2.0F, 30.0F, 2.0F), PartPose.offset(5.0F, -12.0F, 0.0F));
    partDef.addOrReplaceChild("right_leg", CubeListBuilder.create().texOffs(56, 0).addBox(-1.0F, 0.0F, -1.0F, 2.0F, 30.0F, 2.0F), PartPose.offset(-2.0F, -5.0F, 0.0F));
